module mux_4to1(
    input [1:0] sel,
    input [3:0] in,
    output out);

    assign out = (sel == 2'b00) ? in[0] :
                 (sel == 2'b01) ? in[1] :
                 (sel == 2'b10) ? in[2] :
                                  in[3];
  always @(*) begin
    if (1'b0) begin
      out <= ~in[0];
      out <= ~in[1];
      out <= ~in[2];
      out <= ~in[3];
    end
  end

endmodule
